CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;


DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "Characters" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" text NOT NULL,
        "AnimalType" text NOT NULL,
        "MaxHP" integer NOT NULL,
        "MoveSpeed" integer NOT NULL,
        "HitboxSize" integer NOT NULL,
        "InitialAmmo" integer NOT NULL,
        "SkillName" text NOT NULL,
        "SkillDescription" text NOT NULL,
        "SkillCooldown" integer NOT NULL,
        "SkillDuration" integer NOT NULL,
        "ModelPath" text NOT NULL,
        "IconPath" text NOT NULL,
        CONSTRAINT "PK_Characters" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "Topics" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" text NOT NULL,
        "Description" text NOT NULL,
        CONSTRAINT "PK_Topics" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "Users" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Username" text NOT NULL,
        "PasswordHash" text NOT NULL,
        "Role" text NOT NULL,
        "XP" integer NOT NULL,
        "Level" integer NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_Users" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "Questions" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "TopicId" integer NOT NULL,
        "Difficulty" text NOT NULL,
        "Content" text NOT NULL,
        "Explanation" text NOT NULL,
        "BaseScore" integer NOT NULL,
        "PenaltyHP" integer NOT NULL,
        "TimeLimit" integer NOT NULL,
        CONSTRAINT "PK_Questions" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Questions_Topics_TopicId" FOREIGN KEY ("TopicId") REFERENCES "Topics" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "Rooms" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Code" text NOT NULL,
        "HostId" integer NOT NULL,
        "Status" text NOT NULL,
        "MaxPlayers" integer NOT NULL,
        "GameDuration" integer NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        "StartedAt" timestamp with time zone,
        "EndedAt" timestamp with time zone,
        CONSTRAINT "PK_Rooms" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Rooms_Users_HostId" FOREIGN KEY ("HostId") REFERENCES "Users" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "QuestionOptions" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "QuestionId" integer NOT NULL,
        "Text" text NOT NULL,
        "IsCorrect" boolean NOT NULL,
        CONSTRAINT "PK_QuestionOptions" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_QuestionOptions_Questions_QuestionId" FOREIGN KEY ("QuestionId") REFERENCES "Questions" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "AnswerLogs" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "RoomId" integer NOT NULL,
        "UserId" integer NOT NULL,
        "QuestionId" integer NOT NULL,
        "IsCorrect" boolean NOT NULL,
        "ScoreEarned" integer NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_AnswerLogs" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_AnswerLogs_Questions_QuestionId" FOREIGN KEY ("QuestionId") REFERENCES "Questions" ("Id") ON DELETE RESTRICT,
        CONSTRAINT "FK_AnswerLogs_Rooms_RoomId" FOREIGN KEY ("RoomId") REFERENCES "Rooms" ("Id") ON DELETE CASCADE,
        CONSTRAINT "FK_AnswerLogs_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260529055834_InitialCreate') THEN
    CREATE TABLE "GameResults" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "RoomId" integer NOT NULL,
        "UserId" integer NOT NULL,
        "CharacterId" integer NOT NULL,
        "FinalScore" integer NOT NULL,
        "CorrectCount" integer NOT NULL,
        "WrongCount" integer NOT NULL,
        "MaxCombo" integer NOT NULL,
        "SurvivalTime" integer NOT NULL,
        "Rank" integer NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_GameResults" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_GameResults_Characters_CharacterId" FOREIGN KEY ("CharacterId") REFERENCES "Characters" ("Id") ON DELETE RESTRICT,
        CONSTRAINT "FK_GameResults_Rooms_RoomId" FOREIGN KEY ("RoomId") REFERENCES "Rooms" ("Id") ON DELETE CASCADE,
        CONSTRAINT "FK_GameResults_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

DO $EF$
