        "QuestionTopicId" integer NOT NULL,
        "DifficultyMode" text NOT NULL,
        "EnableWeapon" boolean NOT NULL,
        "EnableFruits" boolean NOT NULL,
        "EnableItems" boolean NOT NULL,
        "SafeZoneMode" text NOT NULL,
        "RespawnMode" text NOT NULL,
        CONSTRAINT "PK_RoomSettings" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_RoomSettings_Rooms_RoomId" FOREIGN KEY ("RoomId") REFERENCES "Rooms" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

